import { __unstable__loadDesignSystem } from '@tailwindcss/node'
import { expect, test, vi } from 'vitest'
import * as versions from '../../utils/version'
import { isSafeMigration } from './is-safe-migration'
vi.spyOn(versions, 'isMajor').mockReturnValue(true)

test('debug what currentLineBeforeCandidate contains', async () => {
  let designSystem = await __unstable__loadDesignSystem('@import "tailwindcss";', {
    base: __dirname,
  })

  function debugCheck(example: string, candidate: string) {
    const start = example.indexOf(candidate)
    const end = start + candidate.length

    // Extract the same way is-safe-migration does
    let currentLineBeforeCandidate = ''
    for (let i = start - 1; i >= 0; i--) {
      let char = example.at(i)!
      if (char === '\n') {
        break
      }
      currentLineBeforeCandidate = char + currentLineBeforeCandidate
    }

    console.log(`Example: ${example.replace(/\n/g, '\\n')}`)
    console.log(`Candidate: "${candidate}"`)
    console.log(`currentLineBeforeCandidate: "${currentLineBeforeCandidate}"`)
    console.log(`trimEnd: "${currentLineBeforeCandidate.trimEnd()}"`)
    console.log(`last char: "${currentLineBeforeCandidate.trimEnd().slice(-1)}"`)
    console.log(`matches /[,=:(\[]$/: ${/[,=:(\[]$/.test(currentLineBeforeCandidate.trimEnd())}`)
    console.log('---\n')

    const result = isSafeMigration(candidate, { contents: example, start, end }, designSystem)
    console.log(`isSafeMigration result: ${result}\n\n`)
  }

  debugCheck(`const classes = ["shadow", "blur"];\n`, 'shadow')
  debugCheck(`const x = "shadow";\n`, 'shadow')
  debugCheck(`<div class="shadow"></div>\n`, 'shadow')
  debugCheck(`<div className="blur"></div>\n`, 'blur')
})

