import { __unstable__loadDesignSystem } from '@tailwindcss/node'
import { test } from 'vitest'
import { migrateCandidate } from './migrate'

test('why className is not migrating', async () => {
  let designSystem = await __unstable__loadDesignSystem('@import "tailwindcss";', {
    base: __dirname,
  })

  async function testMigration(example: string, candidate: string) {
    const result = await migrateCandidate(designSystem, {}, candidate, {
      contents: example,
      start: example.indexOf(candidate),
      end: example.indexOf(candidate) + candidate.length,
    })
    console.log(`Example: ${example.replace(/\n/g, '\\n')}`)
    console.log(`Candidate: "${candidate}"`)
    console.log(`Result: "${result}"`)
    console.log(`Changed: ${result !== candidate}`)
    console.log('---')
    return result
  }

  // className should also migrate
