import { __unstable__loadDesignSystem } from '@tailwindcss/node'
import { test } from 'vitest'
import { migrateCandidate } from './migrate'
import { extractRawCandidates } from './candidates'

test('check migration of object property values', async () => {
  let designSystem = await __unstable__loadDesignSystem('@import "tailwindcss";', {
    base: __dirname,
  })

  const example = `{ shadow: "shadow-lg", blur: "blur" }\n`

  console.log(`Example: ${example}`)

  const candidates = await extractRawCandidates(example, 'js')
  console.log(`\nAll extracted candidates:`)
  for (let { rawCandidate, start, end } of candidates) {
    const result = await migrateCandidate(designSystem, {}, rawCandidate, {
      contents: example,
      start,
      end,
    })

    console.log(`  Candidate: "${rawCandidate}" at ${start}-${end}`)
    console.log(`  Context: "${example.substring(Math.max(0, start - 5), Math.min(example.length, end + 5))}"`)
    console.log(`  Result: "${result}"`)
    console.log(`  Changed: ${result !== rawCandidate}`)
    console.log()
  }
})

