import { __unstable__loadDesignSystem } from '@tailwindcss/node'
import { test, expect, vi } from 'vitest'
import * as versions from '../../utils/version'
import migrateContents from './migrate'
vi.spyOn(versions, 'isMajor').mockReturnValue(true)

test('does not migrate string literals in JavaScript contexts', async () => {
  let designSystem = await __unstable__loadDesignSystem('@import "tailwindcss";', {
    base: __dirname,
  })

  // Test case 1: Variable assignments
  let input1 = `const blur = "blur";\nconst shadow = "shadow";\n`
  let result1 = await migrateContents(designSystem, {}, input1, '.js')
  expect(result1).toBe(input1) // Should not change

  // Test case 2: Array elements
  let input2 = `const classes = ["shadow", "blur"];\n`
  let result2 = await migrateContents(designSystem, {}, input2, '.js')
  expect(result2).toBe(input2) // Should not change

  // Test case 3: Object property values
  let input3 = `const config = { filter: "blur", effect: "shadow" };\n`
  let result3 = await migrateContents(designSystem, {}, input3, '.js')
  expect(result3).toBe(input3) // Should not change

  // Test case 4: Function arguments
  let input4 = `doSomething("shadow", "blur");\n`
  let result4 = await migrateContents(designSystem, {}, input4, '.js')
  expect(result4).toBe(input4) // Should not change

  // Test case 5: Class attributes SHOULD still be migrated
  let input5 = `<div class="shadow blur"></div>\n`
  let result5 = await migrateContents(designSystem, {}, input5, '.html')
  expect(result5).toBe(`<div class="shadow-sm blur-sm"></div>\n`) // Should change
})

